var COLUMN_CONFIG_D_TAG = "cyberdeck-columns";
function useColumnSync() {
  const { nostr } = s17();
  const { user } = useCurrentUser();
  const queryClient2 = a2();
  const { data: remoteColumns, isLoading } = ce2({
    queryKey: ["column-sync", user?.pubkey],
    queryFn: async ({ signal }) => {
      if (!user) return null;
      console.log("[ColumnSync] Fetching column config from relays...");
      const abortSignal = AbortSignal.any([signal, AbortSignal.timeout(1e4)]);
      const events = await nostr.query([{
        kinds: [30078],
        authors: [user.pubkey],
        "#d": [COLUMN_CONFIG_D_TAG],
        limit: 1
      }], { signal: abortSignal });
      if (events.length === 0) {
        console.log("[ColumnSync] No remote column config found");
        return null;
      }
      const event = events[0];
      console.log("[ColumnSync] Found remote column config");
      try {
        const columns = JSON.parse(event.content);
        console.log("[ColumnSync] Parsed", columns.length, "columns");
        return columns;
      } catch (error) {
        console.error("[ColumnSync] Failed to parse column config:", error);
        return null;
      }
    },
    enabled: !!user,
    staleTime: 6e4
    // Cache for 1 minute
  });
  const { mutateAsync: saveColumns, isPending: isSaving } = Se2({
    mutationFn: async (columns) => {
      if (!user) {
        throw new Error("User not logged in");
      }
      console.log("[ColumnSync] Publishing", columns.length, "columns to relays...");
      const event = await user.signer.signEvent({
        kind: 30078,
        content: JSON.stringify(columns),
        tags: [
          ["d", COLUMN_CONFIG_D_TAG],
          ["alt", "CyberDeck column configuration"]
        ],
        created_at: Math.floor(Date.now() / 1e3)
      });
      await nostr.event(event, { signal: AbortSignal.timeout(1e4) });
      console.log("[ColumnSync] Column config published successfully");
      return event;
    },
    onSuccess: () => {
      queryClient2.invalidateQueries({ queryKey: ["column-sync", user?.pubkey] });
    }
  });
  return {
    remoteColumns,
    isLoading,
    saveColumns,
    isSaving
  };
}

