function useNote(eventId) {
  const { nostr } = s17();
  return ce2({
    queryKey: ["note", eventId],
    staleTime: 6e4,
    // 60 seconds
    queryFn: async (c46) => {
      const signal = AbortSignal.any([c46.signal, AbortSignal.timeout(5e3)]);
      const events = await nostr.query(
        [
          {
            ids: [eventId],
            limit: 1
          }
        ],
        { signal }
      );
      return events[0] || null;
    },
    enabled: !!eventId
  });
}

